	["Waypoints profile"] = "Perfil de puntos de ruta",
	["When a 'ping' is played, use the indicated sound channel so the volume can be controlled."] = "Cuando se reproduce un 'ping', usa el canal de sonido indicado para que se pueda controlar el volumen.",
